queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?marine_biologists a :Marine_Biologists .
    ?marine_biologists p:name ?name .
    ?marine_biologists p:Experience ?experience_f .
    FILTER(STR(?experience_f) = "5 years")
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?zoologists a :Zoologists .
    ?zoologists p:name ?name .
    ?zoologists p:Experience ?experience_f .
    FILTER(STR(?experience_f) = "5 years")
    BIND(?name AS ?o0)
  }
}

